class Solution {
    public String crackSafe(int n, int k) {
        StringBuilder sb = new StringBuilder();
        for (int i = 0; i < n; i++) {
            sb.append("0");
        }
        int total = (int) Math.pow(k, n);
        int visited = 1;
        while (visited < total) {
            String prefix = sb.substring(sb.length() - (n - 1));
            for (int i = k - 1; i >= 0; i--) {
                String next = prefix + i;
                if (!contains(sb, next)) {
                    sb.append(i);
                    visited++;
                    break;
                }
            }
        }
        return sb.toString();
    }

    private boolean contains(StringBuilder sb, String substr) {
        String str = sb.toString();
        return str.contains(substr);
    }
}
